import React, { useState, useCallback, useRef } from 'react';
import axios from 'axios';
import { jsPDF } from 'jspdf';
import './App.css';

const API = 'http://localhost:8000';

// ─────────────────────────────────────────────────────────────────────────────
// PDF GENERATOR  (matches Arpit's resume format exactly)
// ─────────────────────────────────────────────────────────────────────────────
function buildPDF(d) {
  const doc  = new jsPDF({ unit: 'pt', format: 'a4' });
  const PW   = 595.28;
  const PH   = 841.89;
  const ML   = 44;
  const MR   = 44;
  const TW   = PW - ML - MR;   // 507.28 pt usable width
  let   y    = 50;

  // ── utils ─────────────────────────────────────────────────────────────────
  function guard(need) {
    if (y + need > PH - 38) { doc.addPage(); y = 44; }
  }

  function rule(thickness = 0.75) {
    doc.setDrawColor(15, 15, 15);
    doc.setLineWidth(thickness);
    doc.line(ML, y, PW - MR, y);
  }

  function rText(text, yy, sz, style, rgb) {
    doc.setFont('helvetica', style || 'normal');
    doc.setFontSize(sz || 10.5);
    doc.setTextColor(...(rgb || [30, 30, 30]));
    const w = doc.getTextWidth(text);
    doc.text(text, PW - MR - w, yy);
  }

  // Print inline bold-label + normal value (e.g. "Languages: Python, …")
  // Returns new y after printing
  function inlineBoldValue(label, value, x, maxW) {
    const LH = 15;
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10.5);
    doc.setTextColor(0, 0, 0);
    const lw = doc.getTextWidth(label + ' ');
    doc.text(label, x, y);

    doc.setFont('helvetica', 'normal');
    doc.setTextColor(35, 35, 35);
    const valLines = doc.splitTextToSize(value, maxW - lw);
    doc.text(valLines[0] || '', x + lw, y);
    y += LH;
    for (let i = 1; i < valLines.length; i++) {
      guard(LH);
      doc.text(valLines[i], x + lw, y);
      y += LH;
    }
  }

  // Bullet line — first word of bullet can be bold if it's an action verb
  function bullet(text) {
    const LH   = 15;
    const BX   = ML;
    const TX   = ML + 11;
    const maxW = TW - 11;
    guard(LH);

    // Split "• ActionVerb rest of text…"
    const stripped = text.replace(/^•\s*/, '');
    const spaceIdx = stripped.indexOf(' ');

    if (spaceIdx > 0) {
      const verb = stripped.slice(0, spaceIdx);
      const rest = stripped.slice(spaceIdx); // includes leading space

      // Draw bullet dot
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(10.5);
      doc.setTextColor(35, 35, 35);
      doc.text('•', BX, y);

      // Bold verb
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10.5);
      doc.setTextColor(0, 0, 0);
      const verbW = doc.getTextWidth(verb);
      doc.text(verb, TX, y);

      // Normal rest — may wrap
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(35, 35, 35);
      const restLines = doc.splitTextToSize(rest, maxW - verbW);
      doc.text(restLines[0] || '', TX + verbW, y);
      y += LH;
      for (let i = 1; i < restLines.length; i++) {
        guard(LH);
        doc.text(restLines[i], TX, y);
        y += LH;
      }
    } else {
      // fallback plain
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(10.5);
      doc.setTextColor(35, 35, 35);
      const lines = doc.splitTextToSize('• ' + stripped, TW);
      lines.forEach(line => { guard(LH); doc.text(line, BX, y); y += LH; });
    }
  }

  function secHead(title) {
    y += 8;
    guard(22);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10.5);
    doc.setTextColor(0, 0, 0);
    doc.text(title.toUpperCase(), ML, y);
    y += 3;
    rule();
    y += 9;
  }

  const sk = d.skills || {};

  // ── NAME ──────────────────────────────────────────────────────────────────
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(20);
  doc.setTextColor(0, 0, 0);
  const nw = doc.getTextWidth(d.name || '');
  doc.text(d.name || '', (PW - nw) / 2, y);
  y += 15;

  // ── CONTACT ───────────────────────────────────────────────────────────────
  const parts   = [d.phone, d.email, d.linkedin, d.github].filter(Boolean);
  const contact = parts.join('  |  ');
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(10);
  doc.setTextColor(55, 55, 55);
  const cw = doc.getTextWidth(contact);
  doc.text(contact, (PW - cw) / 2, y);
  y += 10;
  rule(0.6);
  y += 12;

  // ── EXPERIENCE (first — matching Arpit's format) ───────────────────────────
  if (d.experience?.length) {
    secHead('Experience');
    d.experience.forEach(exp => {
      guard(44);

      // Company bold LEFT  +  Dates bold RIGHT
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.setTextColor(0, 0, 0);
      doc.text(exp.company || '', ML, y);
      rText(exp.dates || '', y, 10.5, 'bold', [0, 0, 0]);
      y += 13;

      // Title bold-italic LEFT  +  Location italic RIGHT
      doc.setFont('helvetica', 'bolditalic');
      doc.setFontSize(10.5);
      doc.setTextColor(30, 30, 30);
      doc.text(exp.title || '', ML, y);
      rText(exp.location || '', y, 10.5, 'italic', [70, 70, 70]);
      y += 12;

      (exp.bullets || []).forEach(b => bullet('• ' + b));
      y += 6;
    });
  }

  // ── TECHNICAL SKILLS ──────────────────────────────────────────────────────
  secHead('Technical Skills');
  if (sk.languages)    inlineBoldValue('Languages:', sk.languages, ML, TW);
  if (sk.technologies) inlineBoldValue('Technologies:', sk.technologies, ML, TW);
  if (sk.databases)    inlineBoldValue('Databases:', sk.databases, ML, TW);
  if (sk.other)        inlineBoldValue('Other:', sk.other, ML, TW);
  y += 4;

  // ── PROJECTS ──────────────────────────────────────────────────────────────
  if (d.projects?.length) {
    secHead('Projects');
    d.projects.forEach(proj => {
      guard(38);

      // Project name bold + tech stack right (pipe separated)
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10.5);
      doc.setTextColor(0, 0, 0);
      doc.text(proj.name || '', ML, y);

      // Tech stack after pipe
      const techStr = proj.tech || '';
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9.5);
      doc.setTextColor(70, 70, 70);
      const nameW = doc.getTextWidth((proj.name || '') + '  |  ');
      const pipeX = ML + doc.getTextWidth(proj.name || '');
      doc.text('  |  ', pipeX, y);
      doc.text(techStr, pipeX + doc.getTextWidth('  |  '), y);
      y += 13;

      (proj.bullets || []).forEach(b => bullet('• ' + b));
      y += 6;
    });
  }

  // ── EDUCATION ─────────────────────────────────────────────────────────────
  if (d.education?.length) {
    secHead('Education');
    d.education.forEach(edu => {
      guard(44);

      // School bold + dates right
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.setTextColor(0, 0, 0);
      doc.text(edu.school || '', ML, y);
      rText(edu.dates || '', y, 10.5, 'normal', [30, 30, 30]);
      y += 13;

      // Degree bold-italic + GPA right
      doc.setFont('helvetica', 'bolditalic');
      doc.setFontSize(10.5);
      doc.setTextColor(30, 30, 30);
      doc.text(edu.degree || '', ML, y);
      if (edu.gpa) rText('CGPA: ' + edu.gpa, y, 10.5, 'normal', [50, 50, 50]);
      y += 13;

      if (edu.coursework) {
        guard(15);
        inlineBoldValue('• Relevant Coursework:', edu.coursework, ML, TW);
      }
      y += 5;
    });
  }

  doc.save((d.name || 'resume').replace(/\s+/g, '_') + '_ATS.pdf');
}


// ─────────────────────────────────────────────────────────────────────────────
// EDITABLE FIELD COMPONENTS
// ─────────────────────────────────────────────────────────────────────────────
function Field({ label, value, onChange, mono }) {
  return (
    <div className="field">
      {label && <div className="field-lbl">{label}</div>}
      <input
        className={`field-inp${mono ? ' mono' : ''}`}
        value={value || ''}
        onChange={e => onChange(e.target.value)}
      />
    </div>
  );
}

function Textarea({ label, value, onChange, rows = 4 }) {
  return (
    <div className="field">
      {label && <div className="field-lbl">{label}</div>}
      <textarea
        className="field-ta"
        value={value || ''}
        rows={rows}
        onChange={e => onChange(e.target.value)}
      />
    </div>
  );
}

function Card({ title, children, action }) {
  return (
    <div className="card">
      <div className="card-head">
        <span>{title}</span>
        {action}
      </div>
      {children}
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// LIVE PREVIEW  (white paper look)
// ─────────────────────────────────────────────────────────────────────────────
function Preview({ data: d }) {
  if (!d) return (
    <div className="prev-empty">
      <div className="prev-empty-icon">📄</div>
      <p>Resume preview yahan aayega</p>
    </div>
  );
  const sk = d.skills || {};
  return (
    <div className="prev-paper">
      <div className="prev-name">{d.name}</div>
      <div className="prev-contact">
        {[d.phone, d.email, d.linkedin, d.github].filter(Boolean).join(' | ')}
      </div>
      <div className="prev-rule" />

      {d.summary && (
        <div className="prev-sec">
          <div className="prev-sec-head">Professional Summary</div>
          <p className="prev-body">{d.summary}</p>
        </div>
      )}

      {d.experience?.length > 0 && (
        <div className="prev-sec">
          <div className="prev-sec-head">Experience</div>
          {d.experience.map((e, i) => (
            <div key={i} className="prev-entry">
              <div className="prev-entry-row">
                <strong>{e.company}</strong>
                <span className="prev-dates">{e.dates}</span>
              </div>
              <div className="prev-entry-row prev-sub">
                <em>{e.title}</em>
                <em className="prev-loc">{e.location}</em>
              </div>
              <ul className="prev-bullets">
                {(e.bullets || []).map((b, j) => (
                  <li key={j}>
                    <BoldFirstWord text={b} />
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      )}

      {(sk.languages || sk.technologies || sk.databases || sk.other) && (
        <div className="prev-sec">
          <div className="prev-sec-head">Technical Skills</div>
          {sk.languages    && <p className="prev-skill"><strong>Languages:</strong> {sk.languages}</p>}
          {sk.technologies && <p className="prev-skill"><strong>Technologies:</strong> {sk.technologies}</p>}
          {sk.databases    && <p className="prev-skill"><strong>Databases:</strong> {sk.databases}</p>}
          {sk.other        && <p className="prev-skill"><strong>Other:</strong> {sk.other}</p>}
        </div>
      )}

      {d.projects?.length > 0 && (
        <div className="prev-sec">
          <div className="prev-sec-head">Projects</div>
          {d.projects.map((p, i) => (
            <div key={i} className="prev-entry">
              <div className="prev-entry-row">
                <strong>{p.name}</strong>
                <span className="prev-tech">{p.tech}</span>
              </div>
              <ul className="prev-bullets">
                {(p.bullets || []).map((b, j) => (
                  <li key={j}><BoldFirstWord text={b} /></li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      )}

      {d.education?.length > 0 && (
        <div className="prev-sec">
          <div className="prev-sec-head">Education</div>
          {d.education.map((e, i) => (
            <div key={i} className="prev-entry">
              <div className="prev-entry-row">
                <strong>{e.school}</strong>
                <span>{e.dates}</span>
              </div>
              <div className="prev-entry-row prev-sub">
                <em>{e.degree}</em>
                {e.gpa && <span>CGPA: {e.gpa}</span>}
              </div>
              {e.coursework && (
                <p className="prev-course">
                  <strong>• Relevant Coursework:</strong> {e.coursework}
                </p>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Helper: bold the first word of a bullet (the action verb)
function BoldFirstWord({ text }) {
  const parts = (text || '').split(' ');
  if (parts.length <= 1) return <span>{text}</span>;
  const first = parts[0];
  const rest  = parts.slice(1).join(' ');
  return <span><strong>{first}</strong> {rest}</span>;
}


// ─────────────────────────────────────────────────────────────────────────────
// ATS SCORE BADGE
// ─────────────────────────────────────────────────────────────────────────────
function ScoreBadge({ score }) {
  const color = score >= 90 ? '#22c55e' : score >= 75 ? '#f59e0b' : '#ef4444';
  return (
    <div className="score-badge" style={{ '--sc': color }}>
      <svg viewBox="0 0 36 36" className="score-ring">
        <circle cx="18" cy="18" r="15.9" fill="none" stroke="#2a2d35" strokeWidth="3" />
        <circle
          cx="18" cy="18" r="15.9" fill="none"
          stroke={color} strokeWidth="3"
          strokeDasharray={`${(score / 100) * 100} 100`}
          strokeLinecap="round"
          transform="rotate(-90 18 18)"
        />
      </svg>
      <span className="score-num" style={{ color }}>{score}</span>
      <div className="score-lbl">ATS Score</div>
    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// EDITOR SECTION
// ─────────────────────────────────────────────────────────────────────────────
function Editor({ data, setData }) {
  const upd = useCallback((path, val) => {
    setData(prev => {
      const next  = JSON.parse(JSON.stringify(prev));
      const parts = path.split('.');
      let   obj   = next;
      for (let i = 0; i < parts.length - 1; i++) obj = obj[parts[i]];
      obj[parts[parts.length - 1]] = val;
      return next;
    });
  }, [setData]);

  const updBullets = (path, txt) =>
    upd(path, txt.split('\n').filter(l => l.trim()));

  const addExp = () => setData(p => ({
    ...p,
    experience: [...(p.experience || []), {
      company: 'Company', title: 'Title', location: 'City, State',
      dates: 'Month Year – Present', bullets: ['Action verb + impact']
    }]
  }));

  const delExp = i => setData(p => ({
    ...p, experience: p.experience.filter((_, idx) => idx !== i)
  }));

  const addProj = () => setData(p => ({
    ...p,
    projects: [...(p.projects || []), {
      name: 'Project Name', tech: 'Tech Stack', bullets: ['Describe the project']
    }]
  }));

  const delProj = i => setData(p => ({
    ...p, projects: p.projects.filter((_, idx) => idx !== i)
  }));

  return (
    <div className="editor-scroll">

      {/* Contact */}
      <Card title="Contact Information">
        <div className="g2">
          <Field label="Full Name"  value={data.name}     onChange={v => upd('name', v)} />
          <Field label="Phone"      value={data.phone}    onChange={v => upd('phone', v)} />
          <Field label="Email"      value={data.email}    onChange={v => upd('email', v)} />
          <Field label="LinkedIn"   value={data.linkedin} onChange={v => upd('linkedin', v)} />
          <Field label="GitHub"     value={data.github}   onChange={v => upd('github', v)} />
        </div>
      </Card>

      {/* Summary */}
      <Card title="Professional Summary">
        <Textarea value={data.summary} onChange={v => upd('summary', v)} rows={3} />
      </Card>

      {/* Experience */}
      <Card
        title="Work Experience"
        action={<button className="btn-add" onClick={addExp}>+ Add</button>}
      >
        {(data.experience || []).map((e, i) => (
          <div key={i} className="list-item">
            <div className="list-item-hdr">
              <span className="item-num">Experience {i + 1}</span>
              <button className="btn-del" onClick={() => delExp(i)}>Remove</button>
            </div>
            <div className="g2">
              <Field label="Company"  value={e.company}  onChange={v => upd(`experience.${i}.company`, v)} />
              <Field label="Title"    value={e.title}    onChange={v => upd(`experience.${i}.title`, v)} />
              <Field label="Location" value={e.location} onChange={v => upd(`experience.${i}.location`, v)} />
              <Field label="Dates"    value={e.dates}    onChange={v => upd(`experience.${i}.dates`, v)} />
            </div>
            <Textarea
              label="Bullet Points (ek line = ek bullet)"
              value={(e.bullets || []).join('\n')}
              onChange={v => updBullets(`experience.${i}.bullets`, v)}
              rows={6}
            />
          </div>
        ))}
      </Card>

      {/* Skills */}
      <Card title="Technical Skills">
        <Field label="Languages"    value={data.skills?.languages}    onChange={v => upd('skills.languages', v)} />
        <Field label="Technologies" value={data.skills?.technologies} onChange={v => upd('skills.technologies', v)} />
        <Field label="Databases"    value={data.skills?.databases}    onChange={v => upd('skills.databases', v)} />
        <Field label="Other"        value={data.skills?.other}        onChange={v => upd('skills.other', v)} />
      </Card>

      {/* Projects */}
      <Card
        title="Projects (2 required)"
        action={<button className="btn-add" onClick={addProj}>+ Add</button>}
      >
        {(data.projects || []).map((p, i) => (
          <div key={i} className="list-item">
            <div className="list-item-hdr">
              <span className="item-num">Project {i + 1}</span>
              <button className="btn-del" onClick={() => delProj(i)}>Remove</button>
            </div>
            <div className="g2">
              <Field label="Project Name" value={p.name} onChange={v => upd(`projects.${i}.name`, v)} />
              <Field label="Tech Stack"   value={p.tech} onChange={v => upd(`projects.${i}.tech`, v)} />
            </div>
            <Textarea
              label="Bullet Points (5-6 bullets, ek line = ek bullet)"
              value={(p.bullets || []).join('\n')}
              onChange={v => updBullets(`projects.${i}.bullets`, v)}
              rows={5}
            />
          </div>
        ))}
      </Card>

      {/* Education */}
      <Card title="Education">
        {(data.education || []).map((e, i) => (
          <div key={i} className="list-item">
            <div className="list-item-hdr">
              <span className="item-num">Education {i + 1}</span>
            </div>
            <div className="g2">
              <Field label="School"     value={e.school}     onChange={v => upd(`education.${i}.school`, v)} />
              <Field label="Degree"     value={e.degree}     onChange={v => upd(`education.${i}.degree`, v)} />
              <Field label="Dates"      value={e.dates}      onChange={v => upd(`education.${i}.dates`, v)} />
              <Field label="CGPA"       value={e.gpa}        onChange={v => upd(`education.${i}.gpa`, v)} />
              <div className="span2">
                <Field label="Relevant Coursework" value={e.coursework} onChange={v => upd(`education.${i}.coursework`, v)} />
              </div>
            </div>
          </div>
        ))}
      </Card>

    </div>
  );
}


// ─────────────────────────────────────────────────────────────────────────────
// MAIN APP
// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const [step,    setStep]    = useState('input');   // 'input' | 'result'
  const [oldCV,   setOldCV]   = useState('');
  const [jobDesc, setJobDesc] = useState('');
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState('');
  const [data,    setData]    = useState(null);
  const prevRef = useRef(null);

  async function generate() {
    if (!oldCV.trim() || !jobDesc.trim()) {
      setError('Dono fields fill karein.');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const res = await axios.post(`${API}/generate`, {
        old_resume:      oldCV,
        job_description: jobDesc,
      });
      setData(res.data.resume);
      setStep('result');
    } catch (e) {
      setError(e.response?.data?.detail || e.message || 'Kuch galat hua.');
    } finally {
      setLoading(false);
    }
  }

  function copyText() {
    if (!data) return;
    const sk = data.skills || {};
    const lines = [
      data.name,
      [data.phone, data.email, data.linkedin, data.github].filter(Boolean).join(' | '),
      '',
      ...(data.experience?.length ? [
        'EXPERIENCE',
        ...(data.experience.flatMap(e => [
          `${e.company}  |  ${e.title}  |  ${e.dates}  |  ${e.location}`,
          ...(e.bullets || []).map(b => '• ' + b),
          ''
        ]))
      ] : []),
      'TECHNICAL SKILLS',
      sk.languages    ? 'Languages: ' + sk.languages : '',
      sk.technologies ? 'Technologies: ' + sk.technologies : '',
      sk.databases    ? 'Databases: ' + sk.databases : '',
      sk.other        ? 'Other: ' + sk.other : '',
      '',
      ...(data.projects?.length ? [
        'PROJECTS',
        ...(data.projects.flatMap(p => [
          `${p.name}  |  ${p.tech}`,
          ...(p.bullets || []).map(b => '• ' + b),
          ''
        ]))
      ] : []),
      ...(data.education?.length ? [
        'EDUCATION',
        ...(data.education.flatMap(e => [
          `${e.school}  |  ${e.degree}  |  CGPA: ${e.gpa || ''}  |  ${e.dates}`,
          e.coursework ? '• Relevant Coursework: ' + e.coursework : '',
          ''
        ]))
      ] : []),
    ].filter(l => l !== undefined).join('\n');
    navigator.clipboard.writeText(lines);
  }

  // ── INPUT SCREEN ──────────────────────────────────────────────────────────
  if (step === 'input') {
    return (
      <div className="input-screen">
        <div className="input-box">
          <div className="input-logo">
            <span className="logo-badge">ATS</span>
            <h1>Resume Builder <span className="v2">v2</span></h1>
          </div>
          <p className="input-sub">
            Job description paste karo → AI tumhara resume tailor kar dega.<br />
            ATS score 90–100 guaranteed.
          </p>

          <div className="input-pair">
            <div className="input-half">
              <label className="inp-lbl">Purana Resume (plain text)</label>
              <textarea
                className="big-ta"
                placeholder="Copy-paste your existing resume here..."
                value={oldCV}
                onChange={e => setOldCV(e.target.value)}
              />
            </div>
            <div className="input-half">
              <label className="inp-lbl">Job Description</label>
              <textarea
                className="big-ta"
                placeholder="Paste the full job description here..."
                value={jobDesc}
                onChange={e => setJobDesc(e.target.value)}
              />
            </div>
          </div>

          {error && <div className="inp-err">{error}</div>}

          <button
            className="gen-btn"
            onClick={generate}
            disabled={loading}
          >
            {loading
              ? <><span className="spin" /> Generating ATS Resume…</>
              : '✦ Generate ATS Resume'}
          </button>

          {loading && (
            <div className="loading-steps">
              <div className="ls-row"><span className="ls-dot active" />Analyzing job description…</div>
              <div className="ls-row"><span className="ls-dot" />Matching keywords…</div>
              <div className="ls-row"><span className="ls-dot" />Crafting bullet points…</div>
              <div className="ls-row"><span className="ls-dot" />Optimizing ATS score…</div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── RESULT SCREEN ─────────────────────────────────────────────────────────
  return (
    <div className="result-screen">

      {/* Top bar */}
      <header className="topbar">
        <div className="topbar-left">
          <button className="back-btn" onClick={() => setStep('input')}>← Back</button>
          <span className="topbar-title">ATS Resume Builder</span>
        </div>
        <div className="topbar-right">
          {data?.ats_score && <ScoreBadge score={data.ats_score} />}
          <button className="tb-btn" onClick={copyText}>📋 Copy Text</button>
          <button className="tb-btn tb-primary" onClick={() => data && buildPDF(data)}>
            ⬇ Download PDF
          </button>
        </div>
      </header>

      <div className="result-body">
        {/* Left: Editor */}
        <aside className="editor-panel">
          <div className="panel-head">Editor <span className="editable-tag">editable</span></div>
          {data && <Editor data={data} setData={setData} />}
        </aside>

        {/* Right: Preview */}
        <section className="preview-panel" ref={prevRef}>
          <div className="panel-head">Live Preview</div>
          <Preview data={data} />
        </section>
      </div>
    </div>
  );
}
